INSERT INTO `data_2311` (`id`, `project_id`, `batch_id`, `name`, `sort`, `created_at`, `updated_at`, `data_key`, `data_parent_id`) VALUES (11, 799, 463, 'AI，即人工智能（Artificial Intelligence），是一门研究如何让机器模拟人类智能的学科。它涉及到构建可以感知、推理、学习和决策的智能系统，以解决复杂问题和实现人类类似的任务。', 1, 1699422123, 1699422123, '', 0);
INSERT INTO `data_2311` (`id`, `project_id`, `batch_id`, `name`, `sort`, `created_at`, `updated_at`, `data_key`, `data_parent_id`) VALUES (12, 799, 463, 'AI的技术包括机器学习、自然语言处理、计算机视觉、专家系统等。目前，AI已经广泛应用于各个领域，如医疗、金融、交通、娱乐等，使得机器能够自动化执行某些任务，从而提高效率和准确性。', 2, 1699422123, 1699422123, '', 0);
INSERT INTO `data_2311` (`id`, `project_id`, `batch_id`, `name`, `sort`, `created_at`, `updated_at`, `data_key`, `data_parent_id`) VALUES (13, 799, 463, 'AI大模型是指规模庞大的人工智能模型，这些模型具有更多的参数、更复杂的结构和更强大的计算能力。大模型能够处理更复杂的任务，具备更强的学习和推理能力，并在各种领域中取得更好的性能表现。', 3, 1699422123, 1699422123, '', 0);
INSERT INTO `data_2311` (`id`, `project_id`, `batch_id`, `name`, `sort`, `created_at`, `updated_at`, `data_key`, `data_parent_id`) VALUES (14, 799, 463, '大模型的典型代表是深度学习模型，如深度神经网络。它们通常具有数以百万计甚至数以亿计的参数，能够从大量的数据中学习并提取特征，以完成复杂的任务，如图像识别、语音识别、自然语言处理等。', 4, 1699422123, 1699422123, '', 0);
INSERT INTO `data_2311` (`id`, `project_id`, `batch_id`, `name`, `sort`, `created_at`, `updated_at`, `data_key`, `data_parent_id`) VALUES (15, 799, 463, '大模型又分为公有大模型和私有大模型。公有大模型和私有大模型是指在人工智能领域中使用的预训练模型的不同方式。', 5, 1699422123, 1699422123, '', 0);
INSERT INTO `data_2311` (`id`, `project_id`, `batch_id`, `name`, `sort`, `created_at`, `updated_at`, `data_key`, `data_parent_id`) VALUES (16, 799, 463, '公有大模型是由大型技术公司或研究机构开发和训练的，并且是对公众开放使用的预训练模型。这些模型通常使用大量的计算资源和数据进行训练，可以在多种任务上表现出色。', 6, 1699422123, 1699422123, '', 0);
INSERT INTO `data_2311` (`id`, `project_id`, `batch_id`, `name`, `sort`, `created_at`, `updated_at`, `data_key`, `data_parent_id`) VALUES (17, 799, 463, '一些著名的公有大模型包括 OpenAI 的GPT系列、Google的BARD和Microsoft 的Turing NLG。这些大模型能力强大，但是不能针对于企业的特定场景去做专业，细致化的生成。', 7, 1699422123, 1699422123, '', 0);
INSERT INTO `data_2311` (`id`, `project_id`, `batch_id`, `name`, `sort`, `created_at`, `updated_at`, `data_key`, `data_parent_id`) VALUES (18, 799, 463, '私有大模型是由个人、组织或企业自己独立训练的预训练模型。对于某些特定场景或需求，私有大模型可以更好地满足用户的定制化需求。', 8, 1699422123, 1699422123, '', 0);
INSERT INTO `data_2311` (`id`, `project_id`, `batch_id`, `name`, `sort`, `created_at`, `updated_at`, `data_key`, `data_parent_id`) VALUES (19, 799, 463, '私有大模型的训练通常需要投入大量的计算资源和数据，并需要相关领域的专业知识。这些私有大模型在商业领域中广泛应用，比如在金融、医疗、自动驾驶等领域。', 9, 1699422123, 1699422123, '', 0);
INSERT INTO `data_2311` (`id`, `project_id`, `batch_id`, `name`, `sort`, `created_at`, `updated_at`, `data_key`, `data_parent_id`) VALUES (20, 799, 463, 'AIGC（AI Generated Content）是利用人工智能来生成你所需要的内容，GC的意思是创作内容。与之相对应的概念中，比较熟知的还有PGC，是专业人员用来创作内容；UGC是用户自己创造内容，顾名思义AIGC是利用人工智能来创造内容。', 10, 1699422123, 1699422123, '', 0);
INSERT INTO `data_2311` (`id`, `project_id`, `batch_id`, `name`, `sort`, `created_at`, `updated_at`, `data_key`, `data_parent_id`) VALUES (21, 799, 463, 'GPT是AIGC的一个种类。GPT的全称，是Generative Pre-Trained Transformer（生成式预训练转换器）。是一种基于互联网的、可用数据来训练的、文本生成的深度学习模型。', 11, 1699422123, 1699422123, '', 0);
INSERT INTO `data_2311` (`id`, `project_id`, `batch_id`, `name`, `sort`, `created_at`, `updated_at`, `data_key`, `data_parent_id`) VALUES (22, 800, 464, 'AI，即人工智能（Artificial Intelligence），是一门研究如何让机器模拟人类智能的学科。它涉及到构建可以感知、推理、学习和决策的智能系统，以解决复杂问题和实现人类类似的任务。', 1, 1699423083, 1700040670, '', 0);
