INSERT INTO `template` (`id`, `site_id`, `category_id`, `name`, `parent_id`, `project_id`, `user_id`, `sort`, `status`, `type`, `config`, `created_at`, `updated_at`) VALUES (401, 15, 1, 'picture_review.1699417241', 0, 0, 25, 1699417241, 0, 1, '[{\"type\":\"show-text\",\"text\":\"<h4>\\n\\t<span><strong>• &nbsp;先判断图片是否清晰，然后分析图中人物表情</strong></span>\\n</h4>\\n<p>\\n\\t<span><span style=\\\"color:#999999;\\\">&nbsp; &nbsp; &nbsp; 如判断图片为不清晰，则无需标记。</span><span style=\\\"color:#999999;\\\"></span></span> \\n</p>\",\"id\":\"e60a4l7ss4m\"},{\"type\":\"layout\",\"column0\":{\"span\":18,\"children\":[{\"type\":\"task-file-placeholder\",\"header\":\"图片文件占位符: \",\"tips\":\"\",\"id\":\"2dab4adb-35d2-4adb-8f13-4f759517aa9e\",\"anchor\":\"image_url\"},{\"type\":\"form-radio\",\"header\":\"请在下列选项中选择一个合适的选项: \",\"tips\":\"\",\"vertical\":false,\"data\":[{\"checked\":true,\"text\":\"选项一\"},{\"checked\":false,\"text\":\"选项二\"},{\"checked\":false,\"text\":\"选项三\"}],\"value\":\"选项一\",\"required\":false,\"id\":\"4b893011-dda3-4a48-bf04-0b7f7edb671c\",\"rules\":[]}]},\"column1\":{\"span\":6,\"children\":[{\"type\":\"form-radio\",\"header\":\"图的表情为：\",\"tips\":\"\",\"vertical\":false,\"data\":[{\"checked\":false,\"text\":\"悲伤\"},{\"checked\":false,\"text\":\"愤怒\"},{\"checked\":false,\"text\":\"开心\"},{\"checked\":false,\"text\":\"平静\"},{\"text\":\"hh\",\"checked\":false}],\"required\":false,\"id\":\"89jvtkvsf17\"}]},\"id\":\"77074949-25c5-4231-acba-f31beae52f91\",\"ratio\":3,\"scene\":\"edit\"}]', 1699417241, 1700044152);
INSERT INTO `template` (`id`, `site_id`, `category_id`, `name`, `parent_id`, `project_id`, `user_id`, `sort`, `status`, `type`, `config`, `created_at`, `updated_at`) VALUES (402, 15, 3, 'text_review.1699421831', 0, 0, 25, 1699421831, 0, 1, '[{\"type\":\"show-text\",\"text\":\"<h4>\\n\\t<strong>• &nbsp;请先判断针对图中的转录内容是否准确。</strong>\\n</h4>\\n<p>\\n\\t<strong>&nbsp; </strong><span style=\\\"color:#999999;\\\">&nbsp; &nbsp;请仔细审核，精确到字。</span> \\n</p>\",\"id\":\"r7b55tpu13s\"},{\"type\":\"layout\",\"column0\":{\"span\":18,\"children\":[{\"type\":\"text-file-placeholder\",\"header\":\"文本文件占位符: \",\"tips\":\"\",\"id\":\"4c22a38a-7d57-44f5-b524-de3104376448\",\"anchor\":\"text_url\"}]},\"column1\":{\"span\":6,\"children\":[{\"type\":\"show-text\",\"text\":\"<h4>\\n\\t<strong>转录内容</strong>\\n</h4>\\n<p>\\n\\t<span style=\\\"color:#999999;\\\">这是左侧文件中的一段转录的文字，此任务是需内容审核，需要操作员判断这段文字的对错。</span>\\n</p>\",\"id\":\"xs8v8scgay\"},{\"type\":\"form-radio\",\"header\":\"1. 请判断转录是否准确：\",\"tips\":\"\",\"vertical\":false,\"data\":[{\"checked\":true,\"text\":\"准确\"},{\"checked\":false,\"text\":\"不准确\"}],\"required\":false,\"id\":\"1x29uq4v66e\"},{\"type\":\"multi-input\",\"header\":\"2. 若转录不准确，请您进行修改\",\"tips\":\"转录部分可复制。\",\"required\":false,\"id\":\"b6xr0me5h88\"}]},\"id\":\"b95877ef-e1a5-49c4-b2a1-743015e42492\",\"ratio\":3,\"scene\":\"edit\"}]', 1699421831, 1700032457);
